head.script:
//==================================================================================================================
// id       : fi_205_01_01b
// 이름     : 연마감
// 경로     : 재무회계/일반회계/연마감/
// 사용계정 : 내부
// 파라미터 :
//            IN  :
//            OUT :
//
// 비고     :
//
// 업로드   :
// 다운로드 : 
// 레포트   :
// 호출     : 
//            fi_100_02_02p.jsp(회사조회팝업) - 미호출
//            fi_204_03_10p_01.jsp(재무제표상세팝업)
//==================================================================================================================

// 로그인사용자 정보
scwin.vLoginCoCd     =  "";  // 소속 자회사 
scwin.vLoginCoClsCd  =  "";  // 회계_회사구분('CO035' : 0:동부 EXPRESS)
scwin.vUserHomeClsCd =  "";  // 사용자소속구분코드 
scwin.privAdmin      =  "";  // 어드민권한
scwin.userId         =  "";  // 사용자ID
scwin.vCoCd          =  "";  // 회사코드
scwin.vCoClsCd       =  "";  // 소속회사종류 : 회계_회사구분('CO035' : 0:동부 EXPRESS)

scwin.vAdminYn       =  "";  // 어드민여부
scwin.userEmpNo      =  "";  // 사용자번호

scwin.ed_coCd_hidVal =  "";	// 히든값
scwin.txtCoClsCd     =  "";	// 회사구분

scwin.isStarted            = true;  // 최초 이벤트 여부 (자회사 구분 로직을 최초 한번만 실행-팝업 리턴 시간차)

scwin.isSubCompany         = false;  // 자회사여부

scwin.closeYmSearch  =  "";  // 조회용 결산년월 (00을 한번만 붙임)

scwin.onpageload = function() {

    console.log("====== onpageload ==================");

    // 회원정보를 json 데이터로 모두 받음
    let memJson = $c.data.getMemInfo();

    // 로그인 정보 추출
    let coCd    = $c.gus.cfIsNull( $c.data.getMemInfo("coCd") ) ? '' : $c.data.getMemInfo("coCd");
    let coClsCd = $c.gus.cfIsNull( $c.data.getMemInfo("coClsCd") ) ? '' : $c.data.getMemInfo("coClsCd");
    let userHomeClsCd = $c.data.getMemInfo("userHomeClsCd");  // 사용자소속구분코드
    let userId     = $c.data.getMemInfo("userId");
    let privAdmin  = $c.data.getMemInfo("privAdmin");
    let empNo      = $c.data.getMemInfo("empNo");

    scwin.vLoginCoCd     = coCd;
    scwin.vLoginCoClsCd  = coClsCd;
    scwin.vUserHomeClsCd = userHomeClsCd;

    scwin.vCoCd          = coCd;      
    scwin.vCoClsCd       = coClsCd;   
    scwin.userId         = userId;
    scwin.vAdminYn       = privAdmin;
    scwin.userEmpNo      = empNo;

    console.log("▶▶ vLoginCoCd : "+ scwin.vLoginCoCd +"   loginCoClsCd : "+ scwin.vLoginCoClsCd );
    console.log("▶▶ vCoCd      : "+ scwin.vCoCd +"   vCoClsCd : "+ scwin.vCoClsCd );
    console.log("▶▶ userId     : "+ scwin.userId +"   userEmpNo : "+ scwin.userEmpNo);
    console.log("▶▶ vUserHomeClsCd : "+ scwin.vUserHomeClsCd +"   vAdminYn : "+ scwin.vAdminYn);
//    console.log("▶▶ memJson : "+ JSON.stringify(memJson));

};


//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    console.log("==-==-== onUdcCompleted");

    // 2025-10-14 : 작성일자 포커스 위치 이동
    $p.setTimeout(function() {

        var thisYy = $c.date.getServerDateTime("yyyy");

        // ds_search.NameString(1,"closeYm") =  "<%=DDate.getDate().substring(0,4)%>";
        ds_search.set("closeYm", thisYy);

    	// f_Header();
	    scwin.f_setCompanyInfo(); //자회사여부

        ica_closeYm.focus();

    }, {"delay":50});
};


// @@ ====== 준비 ============================================================================== //

//-------------------------------------------------------------------------
// 자회사 회계 시스템 추가에 따른 설정 
//-------------------------------------------------------------------------
scwin.f_setCompanyInfo = function() {   
    console.log("=== f_setCompanyInfo (자회사 회계 시스템 설정)");

	// 사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
	if( scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD )  {
		scwin.vLoginCoCd    = ACConstants.CO_CD_DONGBU ;
		scwin.vLoginCoClsCd = ACConstants.CO_CLS_CD_DONGBU ;
	}

	ed_coCd.setValue( scwin.vLoginCoCd );

	scwin.f_PopUpCompanyInfo('T');  // 속도 지연 문제
    // console.log("  ▲△ openCompanyPopup  [호출전]");
    // console.log("  △▲ openCompanyPopup  [호출후]");
};


// @@ ====== 조회 ============================================================================== //

//-------------------------------------------------------------------------
// 조회(연마감)
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function() {
    console.log("====== f_Retrieve ==================");

    let ret = await $c.gus.cfValidate([ed_coCd, ica_closeYm]);

	if ( !ret )
	   return false;

  	if(lc_flag.getValue()=="1"){
	  	// 계정이관
	  	var condition = "?closeYm="+ica_closeYm.getValue().trim()+"00&closeDd=00&mgntNo=0";
			condition += "&wrkNo="+ACConstants.CLOSE_ACCTCD_TRANSFER+"&coCd="+ed_coCd.getValue();
	}else{
		// 충당금설정
		var condition = "?closeYm="+ica_closeYm.getValue().trim()+"00&closeDd=00&mgntNo=0";
			condition += "&wrkNo="+ACConstants.CLOSE_PROVISION_SETUP+"&coCd="+ed_coCd.getValue();
	}

    // ds_search.set("closeYm", scwin.closeYmSearch );
    ds_search.set("coClsCd", scwin.txtCoClsCd);

	// ds_yyclose.DataID = "/cm.bc.comnmgnt.closemgnt.RetrieveCloseLogListCMD.do" + condition;

    sbm_search.action = "/cm.bc.comnmgnt.closemgnt.RetrieveCloseLogListCMD.do" + condition;
	// ds_yyclose.Reset();

    var dcJSON = ds_search.getJSON();
    console.log("  *** ds_search : "+ JSON.stringify(dcJSON));

    $c.sbm.execute(sbm_search);
};


//-------------------------------------------------------------------------
// 조회(연마감) submitdone
//-------------------------------------------------------------------------
scwin.sbm_search_submitdone = async function (e) {
    console.log("▷ sbm_search_submitdone");

// <script language=JavaScript for=ds_yyclose event=OnLoadCompleted(rowCnt)>
//   cfHideDSWaitMsg(gr_yyclose);
    // cfShowTotalRows(totalRows, rowCnt);

    if(e.responseJSON.GAUCE) {
        ds_yyclose.setJSON(e.responseJSON.GAUCE);
    }

    // if( e.responseJSON.resultDataSet[0].Code != 0 ) return;

    var rowCnt = ds_yyclose.getTotalRow();

    ed_totalRows.setValue(rowCnt);

    if( rowCnt == 0 ){
		await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
	}  
};


// @@ ====== 그리드 / DS ======================================================================= //

//-------------------------------------------------------------------------
//  데이타셋 정렬
//-------------------------------------------------------------------------
scwin.ds_yyclose_ondataload = function () {
// <!-- 연결산조회 DataSet -->
// id="ds_yyclose" classid="<%=DGauceCLSID.DATASET%>">
//  <param name=SortExpr          value=+seq> 
    ds_yyclose.sort("seq", 0);
};


// @@ ====== 이벤트 ============================================================================ //
//-------------------------------------------------------------------------
// 결산년월 변경
//-------------------------------------------------------------------------
scwin.ica_closeYm_onchange = function () {
    scwin.closeYmSearch = "";
    scwin.closeYmSearch = ica_closeYm.getValue().trim()+"00";
};


// @@ ====== 팝업 ============================================================================== //

//-------------------------------------------------------------------------
// 회사코드 돋보기 클릭
//-------------------------------------------------------------------------
scwin.udc_coCd_onclickEvent = function (e) {
    // f_PopUpCompanyInfo();
    scwin.f_PopUpCompanyInfo('F');
};


//-------------------------------------------------------------------------
// 회사 입력 팝업 
//-------------------------------------------------------------------------
scwin.f_PopUpCompanyInfo = function(pWinCloseTF )  {
  	// var rtnList = cfCommonPopUp("retrieveDongbuGroupCompanyInfo"
	// 							,ed_coCd.text, txt_coNm.value
	// 							,pWinCloseTF,null,null,null,null
	// 							,null,null,null,null,null);
    // KYU_TEST : 회사코드 코드 null일 때 팝업 안뜨게 처리 : 2026-01-19
    let pNoDataCloseTF = pWinCloseTF;
    udc_coCd.cfCommonPopUp(scwin.udc_coCd_callBackFunc
                                ,ed_coCd.getValue(), ed_coNm.getValue()
                                ,pWinCloseTF,null,null,null,null
                                ,null,null,null,null,null,null,null,null,pNoDataCloseTF );
};


// @@ ====== 팝업 callBackFunc ================================================================= //

//-------------------------------------------------------------------------
// 회사코드조회 callBackFunc
//-------------------------------------------------------------------------
scwin.udc_coCd_callBackFunc = function(rtnList) {
    console.log("▲ udc_coCd_callBackFunc (회사코드조회 팝업 callBackFunc)");
    console.log("   rtnList ["+rtnList+"]");

	// SET	 
	if(rtnList != null ) { 
		if (rtnList[0] == "N/A") return; 

			// ed_coCd.text = rtnList[0];	// 코드
			// txt_coNm.value = rtnList[5]; // 회사명
			// ed_coCd.hidVal = rtnList[0];  // 히든값
			// txtCoClsCd.value =rtnList[1];	// 회사구분

		ed_coCd.setValue( rtnList[0] );	// 코드
		ed_coNm.setValue( rtnList[5] ); // 회사명 
        scwin.ed_coCd_hidVal = rtnList[0];  // 히든값
		scwin.txtCoClsCd     = rtnList[1];	// 회사구분
	}else{
		ed_coCd.setValue( "" );	// 코드
		ed_coNm.setValue( "" ); // 회사명 
        scwin.ed_coCd_hidVal = "";	// 히든값
		scwin.txtCoClsCd     = "";	// 회사구분
	}

	if(scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU )  {  	// 자회사 회계 시스템 
		scwin.isSubCompany = true;
	}else{
		scwin.isSubCompany = false;
	}

    if ( scwin.isStarted == true ) {  // 최초 이벤트 여부 (자회사 구분 로직을 최초 한번만 실행-팝업 리턴 시간차)

        // KYU_ORDER
	    if('T' == scwin.vAdminYn  ||  !scwin.isSubCompany   ) { // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우 
		    $c.gus.cfEnableObjects([ed_coCd,ed_coNm,btn_coCd]);    
	    }else {
		    $c.gus.cfDisableObjects([ed_coCd,ed_coNm,btn_coCd]);   
	    }
        scwin.isStarted       = false;  // 최초 이벤트 여부 (자회사 구분 로직을 최초 한번만 실행-팝업 리턴 시간차)
    }
};


// @@ ====== 이벤트 ============================================================================ //

//-------------------------------------------------------------------------
// 회사코드 focus out
//-------------------------------------------------------------------------
scwin.udc_coCd_onblurCodeEvent = function (e) {
// <!-- 회사코드 입력시  -->
// language=JavaScript for=ed_coCd event=OnKillFocus()>
	ed_coNm.setValue("");
	scwin.f_PopUpCompanyInfo('T');
};


// @@ ====== 저장 ============================================================================== //

//-------------------------------------------------------------------------
// 연결산 버튼 클릭
//-------------------------------------------------------------------------
scwin.btn_transferAcct_onclick = function (e) {
    scwin.f_YyCloseProcess('1');
};

//-------------------------------------------------------------------------
// 충당금 버튼 클릭
//-------------------------------------------------------------------------
scwin.btn_debtAmt_onclick = function (e) {
    scwin.f_YyCloseProcess('2');
};


//-------------------------------------------------------------------------
// 연결산
//-------------------------------------------------------------------------
scwin.f_YyCloseProcess = async function(flag) {
    console.log("=== f_YyCloseProcess (연결산)  flag ["+flag+"] (1: 연결산, 2: 충당금)");

	// if (!cfValidate([ed_closeYm]))

    let ret = await $c.gus.cfValidate([ica_closeYm]);

	if ( !ret )
	    return false;

	// 마감체크
    let retClose = await scwin.f_JobCloseYN(flag)
	if ( !retClose )
	    return false;

	if(flag=="1") {
        let rtn = await $c.win.confirm( $c.data.getMessage(MSG_CM_CRM_010,"계정이관")  );

        if ( rtn ) {  // 리턴 처리
	  		// ds_search.UseChangeInfo = false;
	  		// tr_yyclose.Action = "/ac.fi.gnrlaccount.yyclose.ProcessAccountTransferCMD.do";

            sbm_yyclose.action = "/ac.fi.gnrlaccount.yyclose.ProcessAccountTransferCMD.do";
	  		// tr_yyclose.Post();
            $c.sbm.execute(sbm_yyclose);
        }
	}else{
        let rtn = await $c.win.confirm( $c.data.getMessage(MSG_CM_CRM_010,"충당금설정")  );

        if ( rtn ) {  // 리턴 처리
		    // ds_search.UseChangeInfo = false;
		    // tr_yyclose.Action = "/ac.fi.gnrlaccount.yyclose.ProcessProvisionsSetUpCMD.do";

            sbm_yyclose.action = "/ac.fi.gnrlaccount.yyclose.ProcessProvisionsSetUpCMD.do";
		    // tr_yyclose.Post();
            $c.sbm.execute(sbm_yyclose);
	    }
	}
};

//-------------------------------------------------------------------------
// 연결산 submitdone
//-------------------------------------------------------------------------
scwin.sbm_yyclose_submitdone = function (e) {
    console.log("▷ sbm_yyclose_submitdone");

    if( e.responseJSON.resultDataSet[0].Code != 0 ) return;

    $c.gus.cfAlertMsg("성공적으로 처리되었습니다" );	// 성공적으로삭제하였습니다
};


//-------------------------------------------------------------------------
// 마감체크
//-------------------------------------------------------------------------
scwin.f_JobCloseYN = async function(flag)
{
    console.log("=== f_JobCloseYN (마감체크)  flag ["+flag+"]");

	//cfJobCloseYN(마감요청구분,마감년월,마감일,작업번호,관리번호,리턴구분);
	if(flag=="1"){
        // var isClose = cfJobCloseYN("CUR",ed_closeYm.text.trim()+"00","00",'<%=ACConstants.CLOSE_ACCTCD_TRANSFER%>',"0","","",ed_coCd.text);
        var isClose = await udc_closeYn.cfJobCloseYN("CUR", ica_closeYm.getValue().trim()+"00", "00",ACConstants.CLOSE_ACCTCD_TRANSFER,"0","","",ed_coCd.getValue() );
	}else{
		// var isClose = cfJobCloseYN("CUR",ed_closeYm.text.trim()+"00","00",'<%=ACConstants.CLOSE_PROVISION_SETUP%>',"0","","",ed_coCd.text);
        var isClose = await udc_closeYn.cfJobCloseYN("CUR", ica_closeYm.getValue().trim()+"00", "00",ACConstants.CLOSE_PROVISION_SETUP,"0","","",ed_coCd.getValue() );
	}

    console.log("  isClose ["+isClose+"]");

	if(isClose=="0"){
		await $c.gus.cfAlertMsg("마감중입니다.");
		return false;
	}else if(isClose=="2"){
		await $c.gus.cfAlertMsg("마감완료가 되었습니다");
		return false;
	}else{
		return true;
	}
};
